      return {
        outcome: "timed_out",
        exitCode: null,
        events: [],
        stdout: "",
        rawStdout: "",
        stderr: "",
      };
    case "cancelled":
      return {
        outcome: "cancelled",
        exitCode: null,
        events: [],
        stdout: "",
        rawStdout: "",
        stderr: "",
      };
